prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName (COUNT(DISTINCT ?end) AS ?endCount) (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId "0ae2e7d8093840cc8a65c475b6275cae" .
  OPTIONAL { ?model bbo:name ?modelName . }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?end a bboExt:EndEvent ;
       tai:belongsTo ?choreo .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?endCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER( (
    (BOUND(?normId) && ?normId = "0ae2e7d8093840cc8a65c475b6275cae") ||
    (BOUND(?origId) && ?origId = "0ae2e7d8093840cc8a65c475b6275cae")
  ))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName
       ?start ?startName
       ?deadNode ?deadNodeName
       ?end ?endName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?deadNode .
  ?deadNode tai:belongsTo ?choreo .

  FILTER NOT EXISTS {
    ?deadNode ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end2 .
    ?end2 a bboExt:EndEvent ; tai:belongsTo ?choreo .
  }

  OPTIONAL {
    ?deadNode bbo:name ?deadNodeName .
  }

  OPTIONAL {
    ?end a bboExt:EndEvent ; tai:belongsTo ?choreo .
    OPTIONAL { ?end bbo:name ?endName . }
  }
}
LIMIT 25
